        "content": "\"use client\";\r\n\r\nimport React from \"react\";\r\nimport { cn } from \"@/lib/utils\";\r\n\r\ninterface DotBackgroundProps {\r\n  className?: string;\r\n  dotSize?: number;\r\n  gap?: number;\r\n  dotColor?: string;\r\n  maskOpacity?: number;\r\n  children?: React.ReactNode;\r\n}\r\n\r\nexport const DotBackground: React.FC<DotBackgroundProps> = React.memo(({\n          className,\n          dotSize = 1,\n          gap = 20,\n          dotColor = \"currentColor\",\n          maskOpacity = 1,\n          children,\n        }) => {\n          return (\n            <div\n              className={cn(\n                \"relative w-full h-full overflow-hidden bg-background flex items-center justify-center\",\n                className\n              )}\n            >\n              <div\n                className=\"absolute inset-0 pointer-events-none\"\n                style={{\n                  backgroundImage: `radial-gradient(${dotColor} ${dotSize}px, transparent ${dotSize}px)`,\n                  backgroundSize: `${gap}px ${gap}px`,\n                  maskImage: `radial-gradient(ellipse at center, black, transparent 80%)`,\n                  WebkitMaskImage: `radial-gradient(ellipse at center, black, transparent 80%)`,\n                  opacity: maskOpacity,\n                }}\n              />\n              \n              <div className=\"relative z-10 w-full\">\n                {children}\n              </div>\n            </div>\n          );\n        });\nDotBackground.displayName = \"DotBackground\";",
        "targetPath": "components/ui/dot-background.tsx"
